import java.util.concurrent.atomic.AtomicInteger;
public class Main {
    public static void main(String[] args) {
        TrackingService s = new TrackingService(80.0);
        AtomicInteger c = new AtomicInteger(0);
        s.addListener(a -> { if (a.getType() == Alert.AlertType.SPEEDING) c.incrementAndGet(); });
        s.registerVehicle("v2", "Car-002", "Car");
        s.updateLocation("v2", new Location(37.7749, -122.4194), 0);
        s.updateLocation("v2", new Location(37.7900, -122.4000), 3);
        System.out.println("OK_2 SPEEDING_COUNT=" + c.get());
    }
}

