import java.util.concurrent.atomic.AtomicInteger;
public class Main {
    public static void main(String[] args) {
        TrackingService s = new TrackingService(200.0);
        AtomicInteger enter = new AtomicInteger(0), exit = new AtomicInteger(0);
        s.addListener(a -> { if (a.getType()==Alert.AlertType.GEOFENCE_ENTER) enter.incrementAndGet(); else if (a.getType()==Alert.AlertType.GEOFENCE_EXIT) exit.incrementAndGet(); });
        s.registerVehicle("v3", "Van", "Van");
        s.addGeoFence("gf1", "WH", new Location(37.7749, -122.4194), 500);
        s.updateLocation("v3", new Location(37.7748, -122.4195), 0);
        s.updateLocation("v3", new Location(37.7900, -122.4000), 60);
        System.out.println("OK_3 ENTER=" + enter.get() + " EXIT=" + exit.get());
    }
}
